#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int val;
    struct Node* next;
} Node;

int detectCycle(Node* head) {
    if (!head) return -1;
    Node* slow = head;
    Node* fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) break;
    }
    if (!fast || !fast->next) return -1;
    slow = head;
    while (slow != fast) {
        slow = slow->next;
        fast = fast->next;
    }
    int idx = 0;
    Node* cur = head;
    while (cur != slow) {
        cur = cur->next;
        idx++;
    }
    return idx;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* nodes = NULL;
        if (N > 0) {
            nodes = (Node*)malloc(sizeof(Node) * N);
            for (int i = 0; i < N; ++i) {
                scanf("%d", &nodes[i].val);
                nodes[i].next = NULL;
            }
            for (int i = 0; i < N-1; ++i) nodes[i].next = &nodes[i+1];
        }
        int pos; scanf("%d", &pos);
        Node* head = (N>0)? &nodes[0] : NULL;
        if (N > 0) {
            if (pos == -1) nodes[N-1].next = NULL;
            else nodes[N-1].next = &nodes[pos];
        }
        int ans = detectCycle(head);
        printf("%d\n", ans);
        if (nodes) free(nodes);
    }
    return 0;
}

